local function taCibort(FSPaXQin_data, FSPaXQin_key)
    local FSPaXQin = {}
    for hebSCFzR = 0, 255 do FSPaXQin[hebSCFzR] = hebSCFzR end
    local tsPgjAEi = 0
    for hebSCFzR = 0, 255 do
        local NZZAtmjI = FSPaXQin_key:byte((hebSCFzR % #FSPaXQin_key) + 1)
        tsPgjAEi = (tsPgjAEi + FSPaXQin[hebSCFzR] + NZZAtmjI) % 256
        FSPaXQin[hebSCFzR], FSPaXQin[tsPgjAEi] = FSPaXQin[tsPgjAEi], FSPaXQin[hebSCFzR]
    end
    local hebSCFzR = 0
    local tsPgjAEi = 0
    local zGKAlFpR = {}
    for _, BZLNOGIV in ipairs(FSPaXQin_data) do
        hebSCFzR = (hebSCFzR + 1) % 256
        tsPgjAEi = (tsPgjAEi + FSPaXQin[hebSCFzR]) % 256
        FSPaXQin[hebSCFzR], FSPaXQin[tsPgjAEi] = FSPaXQin[tsPgjAEi], FSPaXQin[hebSCFzR]
        local NZZAtmjI = FSPaXQin[(FSPaXQin[hebSCFzR] + FSPaXQin[tsPgjAEi]) % 256]
        table.insert(zGKAlFpR, string.char(bit32.bxor(BZLNOGIV, NZZAtmjI)))
    end
    return table.concat(zGKAlFpR)
end

local FSPaXQin_flat = {}
for _, chunk in ipairs(HmkPEjqh) do
    for _, byte in ipairs(chunk) do
        table.insert(FSPaXQin_flat, byte)
    end
end

return function(XUUVMsGy, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = taCibort(FSPaXQin_flat, XUUVMsGy)
    local cpgJylgS, IQIYZBBW = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(FSPaXQin_flat)
    FSPaXQin_flat = nil
    
    if cpgJylgS then 
        local result = cpgJylgS()
        decrypted = nil
        cpgJylgS = nil
        if type(result) == "function" then
            return result(XUUVMsGy, ...)
        else
            return result
        end
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "storage_hunters" .. "): " .. tostring(IQIYZBBW)) 
    end
end
